import{_ as o,o as t,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Troubleshoot Journeys Banners","description":"","frontmatter":{"title":"Troubleshoot Journeys Banners","slug":"troubleshoot-journeys-banners"},"headers":[],"relativePath":"developer-hub/troubleshoot-journeys-banners.md","filePath":"developer-hub/troubleshoot-journeys-banners.md"}'),r={name:"developer-hub/troubleshoot-journeys-banners.md"};function s(i,e,l,d,u,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h2 id="error-messages" tabindex="-1">Error Messages <a class="header-anchor" href="#error-messages" aria-label="Permalink to &quot;Error Messages&quot;">​</a></h2><h3 id="web-sdk-errors" tabindex="-1">Web SDK errors <a class="header-anchor" href="#web-sdk-errors" aria-label="Permalink to &quot;Web SDK errors&quot;">​</a></h3><ul><li>You must have the web SDK installed on your website to run a Journey. The Branch SDKs for deferred deep and contextual deep linking help you grow your apps and websites with deep links that power referral systems, sharing links and invites with full attribution and analytics. If you&#39;ve integrated the Web SDK already and you&#39;re still seeing issues see the <a href="./web-troubleshooting.html">Web SDK troubleshooting</a> guide.</li><li>If you do not see the journey loading, confirm with your developers that this was loaded on all web pages.</li></ul><h3 id="app-sdk-warnings" tabindex="-1">App SDK warnings <a class="header-anchor" href="#app-sdk-warnings" aria-label="Permalink to &quot;App SDK warnings&quot;">​</a></h3><p>If you choose to target iOS or Android users but haven’t integrated those SDKs, your Journeys will still show on the correct devices and direct users to your app. However, you won’t be able to get any install or event attribution for your Journeys, and you will not be able to deep link users to content inside your app.</p><p>Be sure to integrate the Branch SDK into your app. If you&#39;ve integrated the iOS SDK already and you&#39;re still seeing issues see the <a href="./ios-troubleshooting.html">iOS SDK troubleshooting</a> guide and/or <a href="./android-troubleshooting.html">Android SDK troubleshooting</a> guide.</p><h3 id="journey-not-displaying" tabindex="-1">Journey not displaying <a class="header-anchor" href="#journey-not-displaying" aria-label="Permalink to &quot;Journey not displaying&quot;">​</a></h3><p>If you are testing a journey and it is not displaying, you should review your <strong>dismissal settings</strong>. If you clicked to dismiss the Journey and you are not in an incognito browser, it will not display when testing. We recommend testing in incognito and to check your dismissal settings.</p><p><strong>iOS 17 Safari Private Browsing:</strong> Branch&#39;s Web SDK does not load when Advanced Tracking Protection on iOS 17 Safari is enabled. These protections are built directly into Safari on top of DuckDuckGo&#39;s ad blocking technology. Due to this configuration, it is the same as using an ad blocker, which prevents our Journey from showing when using Incognito Browsing on iOS 17 Safari.</p><h3 id="audience-rule-warnings" tabindex="-1">Audience rule warnings <a class="header-anchor" href="#audience-rule-warnings" aria-label="Permalink to &quot;Audience rule warnings&quot;">​</a></h3><p>You will see a warning if your audience rules do not add up to 100% and will not be able to proceed to Step 3. If you do not want to address 100% of your audience, set up a blank banner for the audience fragment that you do not want to see a Journey.</p><h3 id="calls-to-branchsubdomain-blocked" tabindex="-1">Calls to [branchsubdomain] blocked <a class="header-anchor" href="#calls-to-branchsubdomain-blocked" aria-label="Permalink to &quot;Calls to [branchsubdomain] blocked&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">INFO</p><p><a href="./add-manage-users-roles-permissions-access.html">Click here</a> to read about the value to use for <code>[branchsubdomain]</code>.</p></div><p>Please make sure to add <code>[branchsubdomain]</code> to the CSP header for your pages. We&#39;ve seen some browsers that attempt to block it outright. You can deliver this in an HTTP header from your web server, or you can add a simple metatag to your site like so:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta http-equiv=&quot;Content-Security-Policy&quot; content=&quot;default-src https://[branchsubdomain]; child-src &#39;none&#39;; object-src &#39;none&#39;&quot;&gt;</span></span></code></pre></div><h3 id="non-mobile-optimized-sites" tabindex="-1">Non-mobile optimized sites <a class="header-anchor" href="#non-mobile-optimized-sites" aria-label="Permalink to &quot;Non-mobile optimized sites&quot;">​</a></h3><p>If you&#39;re not using a mobile viewport tag () because your site isn&#39;t mobile-optimized, Journeys will appear shrunken. Not to worry, here&#39;s a workaround:</p><ol><li><p>Design the banner as you would like it to appear on your site</p></li><li><p>Go to the CSS editor and scroll to the bottom of the CSS code</p></li><li><p>Add two properties to the #branch-banner selector</p><ul><li><code>height: 228;</code></li><li><code>zoom: 3;</code></li></ul></li></ol><p>The image will not look appropriately scaled in the editor view because the dashboard is mobile optimized. Use the preview test link on the Validation screen to make sure the banner appears correctly.</p><h3 id="prevent-overlap-between-top-banners-and-persistent-navigation-bars" tabindex="-1">Prevent overlap between top banners and persistent navigation bars <a class="header-anchor" href="#prevent-overlap-between-top-banners-and-persistent-navigation-bars" aria-label="Permalink to &quot;Prevent overlap between top banners and persistent navigation bars&quot;">​</a></h3><ol><li>From the <strong>Configure Creatives</strong> screen click to the <strong>Page Placement</strong> tab.</li><li>Under <strong>Does this banner scroll with the page, or stay fixed in the frame?</strong> select <strong>sticky</strong>.</li><li>Click <strong>Save &amp; Close</strong>.</li><li>Then, add the following div to your nav</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;div class=&quot;branch-journeys-top&quot;&gt;&lt;/div&gt;</span></span></code></pre></div>',22)])])}const b=o(r,[["render",s]]);export{p as __pageData,b as default};
